#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        long long sum = 0; for (int i = 0; i < N; ++i) { long long x; scanf("%lld", &x); sum += x; }
        if (K == 1) {
            if (sum % 2 == 0) printf("odd\n"); else printf("even\n");
        } else {
            printf("even\n");
        }
    }
    return 0;
}

