import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        s = 0
        for _ in range(N):
            s += int(next(it))
        if K == 1:
            out.append('odd' if s % 2 == 0 else 'even')
        else:
            out.append('even')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

